rss.channel:
{{ site.Title }}
{{ site.BaseURL }}
ru
{{ site.Params.description }}
{{- $issues := where site.RegularPages "Section" "in" (slice "chart" "disc") }}
{{- $static := where site.RegularPages "RelPermalink" "in" (slice "/about/" "/method/") }}
{{- $all := union $issues $static }}
{{- range $all.ByDate.Reverse }}
{{- $c := .Content | replaceRE "<(/?)strong>" "<${1}b>" | replaceRE "<(/?)em>" "<${1}i>" | replaceRE "href=\"/" (printf "href=\"%s" site.BaseURL) }}


{{ .Title }} — Музагрегат
{{ .Permalink }}
{{ .Permalink }}
{{- $pd := .Date }}{{ if $pd.IsZero }}{{ $pd = time.AsTime "2026-07-01T00:00:00Z" }}{{ end }}
{{ $pd.Format "Mon, 02 Jan 2006 15:04:05 -0700" }}
nonadult
native-draft
format-article
comment-all

{{ with .Description }}{{ . }}{{ else }}{{ site.Params.description }}{{ end }}
{{ $c }}
{{- if and (eq .Type "chart") .Params.positions }}
<h2>Чарт: {{ len .Params.positions }} позиций</h2>
<ol>
{{- $nomove := .Params.no_movement }}
{{- range .Params.positions }}
<li>{{ .artist }} — «{{ .track }}»{{ if not $nomove }}{{ if .prev }}{{ $d := sub .prev .rank }}{{ if gt $d 0 }} (▲{{ $d }}){{ else if lt $d 0 }} (▼{{ mul -1 $d }}){{ else }} (=){{ end }}{{ else }} (новинка){{ end }}{{ end }}{{ range .flags }}{{ if eq . "ai" }} ⚙{{ end }}{{ if eq . "foreign_agent" }} ⚑{{ end }}{{ if eq . "wild" }} ◈{{ end }}{{ end }}</li>
{{- end }}
</ol>
<p>⚙ — сделано нейросетью · ⚑ — статус иноагента · ◈ — дикий слой. Полная таблица с движением, лейблами и датами релизов — <a href="{{ .Permalink }}">на сайте</a>.</p>
{{- end }}
{{- if and (eq .Type "disc") .Params.positions }}
<h2>Треклист: {{ len .Params.positions }} треков</h2>
<ol>
{{- range .Params.positions }}
<li>{{ .artist }} — «{{ .track }}»{{ with .role }} — {{ . }}{{ end }}</li>
{{- end }}
</ol>
{{- with .Params.playlist_yandex }}
<p><a href="{{ . }}">Плейлист на Яндекс Музыке</a></p>
{{- end }}
{{- end }}
<p><b>Музагрегат</b> — машина, которая слушает русскую музыку. Свежие выпуски: <a href="{{ site.BaseURL }}">muzagregat.ru</a> и <a href="{{ site.Params.telegram }}">телеграм-канал</a>.</p>

{{- end }}
